"use client";
import { authClient } from "@/lib/auth-client";
import { Check } from "@gravity-ui/icons";
import {
  Button,
  Card,
  Description,
  FieldError,
  Form,
  Input,
  Label,
  TextField,
  toast,
} from "@heroui/react";
import Image from "next/image";
import Link from "next/link";
import { redirect } from "next/navigation";

export default function LoginPage() {
  const onSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    const user = Object.fromEntries(formData.entries());
    console.log("Form Data:", user);

    const { data, error } = await authClient.signIn.email({
      email: user.email, // required
      password: user.password, // required
      //rememberMe: true,
      // callbackURL: "https://example.com/callback",
    });
    if (data) {
      toast.success(
        `Login successful! Welcome back, ${data.user.name || "User"}!`,
      );
      redirect("/");
    }
    if (error) {
      toast.danger(error.message || "An error occurred during login.");
    }
  };

  const handleGoogleSignIn = async () => {
    try {
      await authClient.signIn.social({
        provider: "google",
      });
    } catch (error) {
      console.error("Google Sign-In Error:", error);
      toast.danger("An error occurred during Google sign-in.");
    }
  };

  return (
    <div className="flex min-h-screen flex-col items-center justify-center gap-4 bg-gray-100 p-4">
      <Card>
        <Card.Header className="flex flex-col items-center gap-2">
          <Card.Title className="text-3xl">Login</Card.Title>
          <Card.Description>
            Please enter your email and password to log in.
          </Card.Description>
        </Card.Header>
        <Form className="flex w-96 flex-col gap-4" onSubmit={onSubmit}>
          <Card.Content>
            {/* Email  */}
            <TextField
              isRequired
              name="email"
              type="email"
              validate={(value) => {
                if (!/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(value)) {
                  return "Please enter a valid email address";
                }
                return null;
              }}
            >
              <Label>Email</Label>
              <Input placeholder="john@example.com" />
              <FieldError />
            </TextField>

            {/* password */}
            <TextField
              isRequired
              minLength={8}
              name="password"
              type="password"
              validate={(value) => {
                if (value.length < 8) {
                  return "Password must be at least 8 characters";
                }
                if (!/[A-Z]/.test(value)) {
                  return "Password must contain at least one uppercase letter";
                }
                if (!/[0-9]/.test(value)) {
                  return "Password must contain at least one number";
                }
                return null;
              }}
            >
              <Label>Password</Label>
              <Input placeholder="Enter your password" />
              <Description>
                Must be at least 8 characters with 1 uppercase and 1 number
              </Description>
              <FieldError />
            </TextField>
          </Card.Content>
          <Card.Footer className="">
            <div className="flex w-full justify-between">
              <Link href="#" className="text-sm text-blue-500 hover:underline">
                Forget password?
              </Link>
              <Button type="submit">
                <Check />
                Login
              </Button>
            </div>
          </Card.Footer>
        </Form>
        <div className="flex   flex-col gap-3">
          <Button
            className="w-full"
            variant="outline"
            onClick={() => handleGoogleSignIn()}
          >
            <Image
              width={20}
              height={20}
              src="data:image/png;base64,"
              alt="google-logo"
            ></Image>
            Sign in with Google
          </Button>
        </div>
      </Card>
    </div>
  );
}
